import React, { createContext, useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export const AdminContext = createContext();

const AdminContextProvider = ({ children }) => {
    const [adminToken, setAdminToken] = useState("");
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const url = "http://localhost:5000";

    // Admin login function
    const adminLogin = async (email, password) => {
        setLoading(true);
        try {
            // Abhi ke liye simple hardcoded admin (baad me backend se connect kar sakte ho)
            if (email === "admin@gmail.com" && password === "admin123") {
                const fakeToken = "admin-token-" + Date.now();
                setAdminToken(fakeToken);
                localStorage.setItem("adminToken", fakeToken);
                navigate("/orders");
                return { success: true };
            } else {
                return { 
                    success: false, 
                    message: "Invalid credentials" 
                };
            }

            // Jab backend ready ho to ye use karo:
            
            const response = await axios.post(url + "/api/admin/login", {
                email,
                password
            });

            if (response.data.success) {
                setAdminToken(response.data.token);
                localStorage.setItem("adminToken", response.data.token);
                navigate("/orders");
                return { success: true };
            } else {
                return { success: false, message: response.data.message };
            }
          
        } catch (error) {
            console.error("Admin login error:", error);
            return { success: false, message: "Login failed" };
        } finally {
            setLoading(false);
        }
    };

    // Admin logout
    const adminLogout = () => {
        setAdminToken("");
        localStorage.removeItem("adminToken");
        navigate("/login");
    };

    // Check for existing token on load
    useEffect(() => {
        const token = localStorage.getItem("adminToken");
        if (token) {
            setAdminToken(token);
        }
    }, []);

    const contextValue = {
        adminToken,
        setAdminToken,
        adminLogin,
        adminLogout,
        loading,
        url
    };

    return (
        <AdminContext.Provider value={contextValue}>
            {children}
        </AdminContext.Provider>
    );
};

export default AdminContextProvider;
